<script setup>
import { computed, onMounted, reactive, ref, watch } from "vue";
import axios from "axios";
import Swal from "sweetalert2";
const props = defineProps({ filters: { type: Object, required: true }, dashboard: { type: Object, required: true }, capabilities: { type: Object, default: () => ({}) } });
const goals = ref([]); const loading = ref(false); const goalModal = ref(false); const saving = ref(false); const projection = ref(null); const impact = ref(null);
const goalForm = reactive({ academic_year_id: null, name: "", scope_type: "institution", starts_on: "", ends_on: "", target_rate: 92, status: "active", justification: "", reason: "" });
const simulation = reactive({ future_rate: 90, target_rate: 92, remaining_expected: 0, method: "custom_scenario" });
const observed = computed(() => ({ present: Number(props.dashboard.summary?.present || 0), expected: Number(props.dashboard.summary?.expected || 0) }));
const loadGoals = async () => { loading.value = true; try { const response = await axios.get("/api/attendance-statistics/goals", { params: { academic_year_id: props.filters.academic_year_id } }); goals.value = response.data.data || []; } finally { loading.value = false; } };
const openGoal = () => { Object.assign(goalForm, { academic_year_id: Number(props.filters.academic_year_id), name: "Meta institucional", scope_type: "institution", starts_on: props.dashboard.meta?.academic_year?.starts_at?.slice(0,10) || "", ends_on: props.dashboard.meta?.academic_year?.ends_at?.slice(0,10) || "", target_rate: Number(props.dashboard.summary?.target_rate || 92), status: "active", justification: "", reason: "" }); goalModal.value = true; };
const saveGoal = async () => { saving.value = true; try { await axios.post("/api/attendance-statistics/goals", goalForm); goalModal.value = false; await loadGoals(); await Swal.fire({ icon: "success", title: "Meta creada", timer: 1400, showConfirmButton: false }); } catch (error) { await Swal.fire({ icon: "error", title: "No se pudo guardar", text: error.response?.data?.message || Object.values(error.response?.data?.errors || {}).flat().join(" ") }); } finally { saving.value = false; } };
const simulate = async () => { saving.value = true; try { const response = await axios.post("/api/attendance-statistics/simulate", { academic_year_id: Number(props.filters.academic_year_id), course_section_id: props.filters.course_section_id || null, observed_present: observed.value.present, observed_expected: observed.value.expected, remaining_expected: Number(simulation.remaining_expected || 0), future_rate: Number(simulation.future_rate), target_rate: Number(simulation.target_rate), method: simulation.method }); projection.value = response.data.projection; impact.value = response.data.financial_impact; } catch (error) { await Swal.fire({ icon: "error", title: "No se pudo simular", text: error.response?.data?.message || "Revisa los parámetros." }); } finally { saving.value = false; } };
const progress = (goal) => { const current = Number(props.dashboard.summary?.attendance_rate || 0); return Math.max(0, Math.min(100, (current / Number(goal.target_rate || 1)) * 100)); };
const money = (value, currency = "CLP") => new Intl.NumberFormat("es-CL", { style: "currency", currency, maximumFractionDigits: 0 }).format(Number(value || 0));
watch(() => props.filters.academic_year_id, loadGoals); onMounted(() => { simulation.target_rate = Number(props.dashboard.summary?.target_rate || 92); loadGoals(); });
</script>

<template>
  <div class="goals-stack">
    <section class="goals-panel"><header><div><span>METAS DE ASISTENCIA</span><h2>Cumplimiento institucional</h2><p>Metas versionadas por alcance y periodo.</p></div><button v-if="capabilities.can_manage_goals" type="button" class="btn btn-primary" @click="openGoal"><i class="bx bx-plus"></i>Nueva meta</button></header><div v-if="loading" class="panel-state"><span class="spinner-border"></span>Cargando metas</div><div v-else-if="!goals.length" class="panel-state"><i class="bx bx-target-lock"></i><strong>No hay metas configuradas para este año</strong></div><div v-else class="goal-list"><article v-for="goal in goals" :key="goal.id"><div class="goal-head"><div><strong>{{ goal.name }}</strong><span>{{ goal.scope_type }} · {{ goal.starts_on }} al {{ goal.ends_on }}</span></div><b>{{ Number(goal.target_rate).toLocaleString('es-CL') }}%</b></div><div class="goal-progress"><span :style="{ width: `${progress(goal)}%` }"></span></div><div class="goal-foot"><span>Avance relativo {{ progress(goal).toFixed(1) }}%</span><span>{{ goal.status }}</span></div></article></div></section>
    <section class="simulator-panel"><header><div><span>SIMULADOR TRANSPARENTE</span><h2>Proyección al cierre</h2><p>Escenario explícito, sin decisiones automáticas.</p></div><button type="button" class="help-btn" title="Cómo se calcula" @click="Swal.fire({ title: 'Fórmula de proyección', text: 'Se suman los presentes observados y las asistencias futuras estimadas; el resultado se divide por todos los registros esperados.' })"><i class="bx bx-help-circle"></i></button></header><div class="simulator-grid"><div class="simulation-inputs"><label>Tasa esperada futura <strong>{{ simulation.future_rate }}%</strong><input v-model.number="simulation.future_rate" type="range" min="0" max="100" step="1" /></label><label>Meta <input v-model.number="simulation.target_rate" type="number" min="0" max="100" step=".1" class="form-control" /></label><label>Registros esperados restantes <input v-model.number="simulation.remaining_expected" type="number" min="0" step="1" class="form-control" /></label><label>Método<select v-model="simulation.method" class="form-select"><option value="custom_scenario">Escenario configurable</option><option value="historical_average">Promedio histórico</option><option value="moving_average">Promedio móvil</option><option value="weighted_average">Promedio ponderado</option><option value="linear_trend">Tendencia lineal</option></select></label><button type="button" class="btn btn-primary" :disabled="saving" @click="simulate"><span v-if="saving" class="spinner-border spinner-border-sm"></span><i v-else class="bx bx-line-chart"></i>Calcular escenario</button></div><div class="projection-result"><template v-if="projection"><span>ASISTENCIA PROYECTADA</span><strong>{{ Number(projection.projected_rate).toLocaleString('es-CL') }}%</strong><div><span>Brecha final</span><b>{{ projection.gap }} pp</b></div><div><span>Asistencias futuras requeridas</span><b>{{ projection.required_future_attendances }}</b></div><div><span>Adicionales necesarias</span><b>{{ projection.additional_attendances_needed }}</b></div><p :class="projection.target_is_mathematically_reachable ? 'reachable' : 'unreachable'"><i class="bx" :class="projection.target_is_mathematically_reachable ? 'bx-check-circle' : 'bx-error-circle'"></i>{{ projection.target_is_mathematically_reachable ? 'La meta es alcanzable con los cupos restantes.' : 'La meta no es matemáticamente alcanzable en este escenario.' }}</p><small>{{ projection.assumption }}</small></template><template v-else><i class="bx bx-line-chart"></i><strong>Configura un escenario</strong><span>El resultado y sus supuestos aparecerán aquí.</span></template></div></div>
      <div v-if="impact?.available && capabilities.can_view_financial" class="impact-row"><div><span>Estimación actual</span><strong>{{ money(impact.totals.current_estimate) }}</strong></div><div><span>Estimación proyectada</span><strong>{{ money(impact.totals.projected_estimate) }}</strong></div><div><span>Diferencia</span><strong>{{ money(impact.totals.difference) }}</strong></div><div><span>Impacto por punto</span><strong>{{ money(impact.totals.impact_per_point) }}</strong></div><p>{{ impact.warning }}</p></div>
    </section>
    <div v-if="goalModal" class="attendance-goal-modal-layer" role="dialog" aria-modal="true" aria-label="Nueva meta" @click.self="goalModal = false" @keydown.esc="goalModal = false"><form class="goal-form" @submit.prevent="saveGoal"><header><h3>Nueva meta de asistencia</h3><button type="button" class="help-btn" title="Cerrar" @click="goalModal = false"><i class="bx bx-x"></i></button></header><div class="form-grid"><label>Nombre<input v-model.trim="goalForm.name" class="form-control" required /></label><label>Alcance<select v-model="goalForm.scope_type" class="form-select"><option value="institution">Institucional</option><option value="cycle">Ciclo</option><option value="level">Nivel</option><option value="course">Curso</option><option value="student">Individual</option></select></label><label>Inicio<input v-model="goalForm.starts_on" type="date" class="form-control" required /></label><label>Término<input v-model="goalForm.ends_on" type="date" class="form-control" required /></label><label>Objetivo (%)<input v-model.number="goalForm.target_rate" type="number" min="0" max="100" step=".1" class="form-control" required /></label><label class="full">Justificación<textarea v-model.trim="goalForm.justification" rows="2" class="form-control"></textarea></label><label class="full">Motivo del registro<textarea v-model.trim="goalForm.reason" rows="2" class="form-control" required></textarea></label></div><footer><button type="button" class="btn btn-light" @click="goalModal = false">Cancelar</button><button type="submit" class="btn btn-primary" :disabled="saving">Guardar meta</button></footer></form></div>
  </div>
</template>

<style scoped>
.goals-stack{display:grid;gap:.8rem}.goals-panel,.simulator-panel{border:1px solid #dfe5ec;border-radius:8px;background:#fff}.goals-panel>header,.simulator-panel>header{display:flex;align-items:flex-start;justify-content:space-between;gap:1rem;padding:1rem;border-bottom:1px solid #e7ebf0}.goals-panel>header span,.simulator-panel>header span,.projection-result>span,.impact-row span{color:#6d7889;font-size:.62rem;font-weight:700}.goals-panel h2,.simulator-panel h2{margin:.12rem 0;color:#273244;font-size:1rem}.goals-panel p,.simulator-panel p{margin:0;color:#748094;font-size:.7rem}.goals-panel .btn,.simulation-inputs .btn{display:inline-flex;align-items:center;gap:.35rem}.panel-state{display:flex;align-items:center;justify-content:center;gap:.55rem;min-height:180px;color:#6f7b8c;font-size:.75rem}.panel-state i{font-size:1.6rem}.goal-list{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:.65rem;padding:.8rem}.goal-list article{padding:.75rem;border:1px solid #e2e7ed;border-radius:6px}.goal-head,.goal-foot{display:flex;align-items:flex-start;justify-content:space-between;gap:.5rem}.goal-head strong,.goal-head span{display:block}.goal-head span,.goal-foot{color:#7a8596;font-size:.61rem}.goal-head b{color:#405189;font-size:1.1rem}.goal-progress{height:6px;margin:.65rem 0;background:#edf1f4}.goal-progress span{display:block;height:100%;background:#2b8a66}.simulator-grid{display:grid;grid-template-columns:minmax(300px,.7fr) minmax(320px,1.3fr);gap:1rem;padding:1rem}.simulation-inputs{display:grid;grid-template-columns:1fr 1fr;gap:.7rem}.simulation-inputs label{color:#526071;font-size:.68rem;font-weight:650}.simulation-inputs label:first-child,.simulation-inputs .btn{grid-column:1/-1}.simulation-inputs label strong{float:right}.simulation-inputs input[type=range]{width:100%;margin-top:.6rem}.simulation-inputs .form-control,.simulation-inputs .form-select{margin-top:.25rem;font-size:.73rem}.simulation-inputs .btn{justify-content:center}.projection-result{display:grid;grid-template-columns:1fr 1fr;gap:.5rem;align-content:start;padding:1rem;background:#f6f8fb;border-left:3px solid #405189}.projection-result>span,.projection-result>strong,.projection-result>p,.projection-result>small,.projection-result>i{grid-column:1/-1}.projection-result>strong{color:#273244;font-size:2rem}.projection-result>div{padding:.5rem;background:#fff}.projection-result>div span,.projection-result>div b{display:block}.projection-result>div span{color:#7a8596;font-size:.6rem}.projection-result p{display:flex;align-items:center;gap:.35rem;padding:.55rem}.projection-result p.reachable{background:#e9f7f0;color:#16794b}.projection-result p.unreachable{background:#fff0f1;color:#b43341}.projection-result small{color:#7a8596;font-size:.62rem}.projection-result>i{font-size:2rem;color:#718096}.impact-row{display:grid;grid-template-columns:repeat(4,1fr);border-top:1px solid #e7ebf0}.impact-row>div{padding:.7rem 1rem;border-right:1px solid #e7ebf0}.impact-row span,.impact-row strong{display:block}.impact-row strong{margin-top:.18rem;color:#273244}.impact-row p{grid-column:1/-1;padding:.5rem 1rem;background:#fff8e8;color:#7b5b1d!important}.help-btn{display:grid;place-items:center;width:32px;height:32px;border:1px solid #d9e0e8;border-radius:6px;background:#fff;color:#405189}.attendance-goal-modal-layer{position:fixed;z-index:1085;inset:0;display:grid;place-items:center;padding:1rem;background:rgba(25,34,48,.58);opacity:1}.goal-form{position:relative;z-index:1;width:min(700px,100%);max-height:calc(100vh - 2rem);overflow:auto;border:1px solid #e1e6ed;border-radius:8px;background:#fff;box-shadow:0 24px 64px rgba(18,27,40,.28);opacity:1}.goal-form>header,.goal-form>footer{display:flex;align-items:center;justify-content:space-between;padding:.85rem 1rem;border-bottom:1px solid #e7ebf0;background:#fff}.goal-form h3{margin:0;font-size:1rem}.goal-form>footer{justify-content:flex-end;gap:.4rem;border-top:1px solid #e7ebf0;border-bottom:0}.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:.7rem;padding:1rem;background:#fff}.form-grid label{color:#526071;font-size:.68rem;font-weight:650}.form-grid .full{grid-column:1/-1}.form-grid .form-control,.form-grid .form-select{margin-top:.25rem;font-size:.73rem}@media(max-width:850px){.goal-list{grid-template-columns:1fr}.simulator-grid{grid-template-columns:1fr}.impact-row{grid-template-columns:repeat(2,1fr)}}@media(max-width:520px){.simulation-inputs,.form-grid{grid-template-columns:1fr}.simulation-inputs label:first-child,.simulation-inputs .btn,.form-grid .full{grid-column:auto}.projection-result{grid-template-columns:1fr}.impact-row{grid-template-columns:1fr}.attendance-goal-modal-layer{align-items:end;padding:.5rem}}
</style>
